import { color as d3Color } from 'd3-color';

import { getTokenComputedStyle } from './getTokenComputedStyle.js';
import { SCALE_FALLBACK_COLOR } from '../constants.js';

export const buildRgbaColorWithOpacity = (
  baseColor: string,
  opacity: number = 1,
) => {
  const nameableColor = getTokenComputedStyle(baseColor);
  const convertedColor =
    d3Color(nameableColor) ??
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    d3Color(getTokenComputedStyle(SCALE_FALLBACK_COLOR))!;
  convertedColor.opacity = opacity;

  return convertedColor.formatHex8();
};
